INSERT INTO projects (project_id, company_id, project_code, pre_code, project_name, client_name, remark, created_at, qual_passed, is_winning_bid, exam_registered, exam_status, manager_id, manager_name, status, start_date, end_date, current_phase_id, client_id, overview, approval_status, created_by, pm_ids, project_state_id, assign_status, project_type_id, serial_number, formal_number, formal_year, project_year, is_deleted, competitor_ids, test_type, test_stage, item_state_id, product_name, category_id, week_hours, sponsor_id, budget_amount, actual_company_id, contact_ids, milestone_type_id) VALUES (225, 1, 'SOFU202203006', 'Y-SOFU202203008', '评估PD-L1/ TGF-βRII抗体SHR-1701治疗复发或转移鼻咽癌患者的安全性和耐受性的Ib期临床研究', '江苏恒瑞医药股份有限公司', NULL, '2021-02-04 15:14:00', 0, 0, 0, 0, NULL, NULL, 1, NULL, NULL, 94887, 45, '甲方正在[湖南省肿瘤医院]医院开展一项名为【评估PD-L1/ TGF-βRII抗体SHR-1701治疗复发或转移鼻咽癌患者的安全性和耐受性的Ib期临床研究】；为进一步提高试验项目质量、准确及时录入研究数据，尽可能使该试验项目顺利进行，甲方应研究机构/研究者需求，为其提供临床研究协调员服务，并希望聘请SMO为研究机构提供服务。\n本协议服务期预计为【24】个月，预计入组受试者例数为【6】例', 'pass', 445, '445', 93020, 1, NULL, 8, 6, 2022, 2022, 0, NULL, '141', '22', NULL, NULL, NULL, 0.00, 0, 0.00, 6, NULL, 6);
