INSERT INTO projects (project_id, company_id, project_code, pre_code, project_name, client_name, remark, created_at, qual_passed, is_winning_bid, exam_registered, exam_status, manager_id, manager_name, status, start_date, end_date, current_phase_id, client_id, overview, approval_status, created_by, pm_ids, project_state_id, assign_status, project_type_id, serial_number, formal_number, formal_year, project_year, is_deleted, competitor_ids, test_type, test_stage, item_state_id, product_name, category_id, week_hours, sponsor_id, budget_amount, actual_company_id, contact_ids, milestone_type_id) VALUES (516, 1, NULL, 'Y-SINO202302029', '洛索洛芬钠凝胶贴膏大临床', '杭州百诚医药科技股份有限公司', '杭州百诚为技术转让方，他们与申办方签订的项目标的是包拿到批文，我们报价在参加投标的3方中处于中间位数（2022年9月份）。\n后因药监局对凝胶贴膏的临床指导进行了多方面有关会议，申办方担心会发布新的法规要求，固推迟了3个月，到12月份的时候收到申办方肯定信息，最终放弃继续该项目。', '2023-02-07 09:21:00', 0, 0, 0, 0, NULL, NULL, 1, NULL, NULL, 93423, 443, '杭州百诚为技术转让方，他们与申办方签订的项目标的是包拿到批文，我们报价在参加投标的3方中处于中间位数（2022年9月份）。\n后因药监局对凝胶贴膏的临床指导进行了多方面有关会议，申办方担心会发布新的法规要求，固推迟了3个月，到12月份的时候收到申办方肯定信息，最终放弃继续该项目。', 'pass', 725, '725', 93021, 1, NULL, 29, NULL, NULL, 2023, 0, NULL, NULL, NULL, 93581, '洛索洛芬钠凝胶贴膏', NULL, 0.00, 0, 0.00, 1, '428', 1);
