INSERT INTO projects (project_id, company_id, project_code, pre_code, project_name, client_name, remark, created_at, qual_passed, is_winning_bid, exam_registered, exam_status, manager_id, manager_name, status, start_date, end_date, current_phase_id, client_id, overview, approval_status, created_by, pm_ids, project_state_id, assign_status, project_type_id, serial_number, formal_number, formal_year, project_year, is_deleted, competitor_ids, test_type, test_stage, item_state_id, product_name, category_id, week_hours, sponsor_id, budget_amount, actual_company_id, contact_ids, milestone_type_id) VALUES (574, 1, 'SINO202305001', 'Y-SINO202305001', '心源性卒中多学科协作诊疗模式的真实世界登记研究', '南昌大学 第二附属医院', '1. 乙方向甲方指定的南昌大学第二附属医院提供CRC服务，协助研究者完成本项目相关的、非医学性判断的事务性工作。乙方CRC严格按照国家《药物临床试验质量管理规范》（以下简称“GCP”）等有关政策法规以及临床研究方案、项目管理SOP等规定进行，并协助研究者完成病例入组协调。\n2. 本合同主要工作预计自【2022】年【08】月起至【2023】年【09】月止，服务周期【14】个月。\n3. 乙方应自 【2023】年【10】月起至【2024】年【10】月止协助甲方完成本项目收尾工作。期限届满后若不需要继续履行本项目，则协议自本服务期结束时自动终止。双方也可根据实际需要签订委托协议继续履行本项目，签署补充协议需在第二阶段服务期截止前两个月内，并重新规定新的服务价格和新的服务期限。\n', '2023-05-04 15:51:00', 0, 0, 0, 0, 65, '黄哲', 1, NULL, NULL, 93422, 1282, '1. 乙方向甲方指定的南昌大学第二附属医院提供CRC服务，协助研究者完成本项目相关的、非医学性判断的事务性工作。乙方CRC严格按照国家《药物临床试验质量管理规范》（以下简称“GCP”）等有关政策法规以及临床研究方案、项目管理SOP等规定进行，并协助研究者完成病例入组协调。\n2. 本合同主要工作预计自【2022】年【08】月起至【2023】年【09】月止，服务周期【14】个月。\n3. 乙方应自 【2023】年【10】月起至【2024】年【10】月止协助甲方完成本项目收尾工作。期限届满后若不需要继续履行本项目，则协议自本服务期结束时自动终止。双方也可根据实际需要签订委托协议继续履行本项目，签署补充协议需在第二阶段服务期截止前两个月内，并重新规定新的服务价格和新的服务期限。\n', 'pass', 65, '65', 93020, 1, NULL, 1, 1, 2023, 2023, 0, NULL, NULL, NULL, 93581, NULL, NULL, NULL, 0, 0.00, 1, NULL, 1);
