INSERT INTO projects (project_id, company_id, project_code, pre_code, project_name, client_name, remark, created_at, qual_passed, is_winning_bid, exam_registered, exam_status, manager_id, manager_name, status, start_date, end_date, current_phase_id, client_id, overview, approval_status, created_by, pm_ids, project_state_id, assign_status, project_type_id, serial_number, formal_number, formal_year, project_year, is_deleted, competitor_ids, test_type, test_stage, item_state_id, product_name, category_id, week_hours, sponsor_id, budget_amount, actual_company_id, contact_ids, milestone_type_id) VALUES (784, 1, NULL, 'Y-SINO202601001', '滋肾育胎丸治疗反复种植失败的临床研究  CRO 技术服务项目', '广州白云山中一药业有限公司', '1.试验类别：上市后研究（随机、双盲、安慰剂平行对照临床研究）\n2、试验药物：滋肾育胎丸（国药准字Z44020008）\n3、样本量：878例（对照组439例，试验组439例）\n4、研究单位：全国15家中心（三甲医院生殖科），组长单位为北京大学第三医院。\n5、计划总周期：合同总费用的首期转账到达中标CRO公司、招标方提供合格试验药品（即滋肾育胎丸及滋肾育胎丸模拟丸）及药品质量检验报告之日起计算，42个月内完成并出具盖章总结报告。\n', '2026-01-30 12:00:00', 0, 0, 0, 0, NULL, NULL, 1, NULL, NULL, 93424, 1533, '1.试验类别：上市后研究（随机、双盲、安慰剂平行对照临床研究）\n2、试验药物：滋肾育胎丸（国药准字Z44020008）\n3、样本量：878例（对照组439例，试验组439例）\n4、研究单位：全国15家中心（三甲医院生殖科），组长单位为北京大学第三医院。\n5、计划总周期：合同总费用的首期转账到达中标CRO公司、招标方提供合格试验药品（即滋肾育胎丸及滋肾育胎丸模拟丸）及药品质量检验报告之日起计算，42个月内完成并出具盖章总结报告。\n', 'pass', 970, '970', 93019, 1, NULL, 1, NULL, NULL, 2026, 0, ',12,14,', '21', '139', 93579, '滋生育胎丸', 112, 0.00, 0, 0.00, 1, '2147', 7);
